-- Tenancy: the BRAND_PREDICATE sentinel (below) is replaced with `brand_id = ?` by the serving seam.
CREATE OR REPLACE VIEW brain_serving.mv_metric_roas_all AS
WITH base AS (
  SELECT
    brand_id,
    currency_code,
    platform,
    SUM(attributed_revenue_minor) AS attributed_revenue_minor,
    SUM(spend_minor) AS spend_minor
  FROM brain_serving.semantic_campaign
  WHERE ${BRAND_PREDICATE}
  GROUP BY 1, 2, 3
)
SELECT
  brand_id,
  currency_code,
  platform,
  attributed_revenue_minor,
  spend_minor,
  (CAST(attributed_revenue_minor AS double) / NULLIF(spend_minor, 0)) AS roas
FROM base;
